templates.template:
{{ phrase('cnxfans_gave_you_a_red_ennelope', {
         'name': username_link($user, false, {'defaultname': $alert.username}),
	     'target':  base_url($extra.targetLink),
         'thread': prefix('thread', $extra.prefix_id) . $extra.title ,
		 'title': $extra.title })
	}}

.block.mjc-balance{
	.contentRow-header{
		float: left;
		font-size: 14px;
	}
	.contentRow-title{
		float: right;
		font-size: 14px;
	}
}

@_purchaser-spacing: .75em;
@_purchaser-paddingV: @xf-paddingMedium;
@_purchaser-paddingH: @xf-paddingLarge;
@_bbCodeBlock-expandTriggerHeight: (@xf-bbCodeBlockExpandHeight) / 2;

.purchaser
{
	margin: @_purchaser-spacing 0;
	.xf-bbCodeBlock();
}

.purchaser-title
{
	padding: @_purchaser-paddingV @_purchaser-paddingH;
	.xf-bbCodeBlockTitle();
	.m-clearFix();
}

.purchaser-content
{
	position: relative;
	display: table;
	table-layout: fixed;
	width: 100%;
}

.purchaser-stats {
  display: table-cell;
  width: 90px;
  vertical-align: middle;
  text-align: center;
}

.purchaser-extra {
  display: table-cell;
  vertical-align: middle;
  padding: 10px;
  font-size: 13px;
}

.pairs.pairs--rows > dt {
  display: table-row;
  font-size: 100%;
}
.pairs.pairs--rows > dd {
	display: table-row;
	font-size: 80%;
}

.p-navgroup-link
{
	&.p-navgroup-link--mjc-credits i:after
	{
		.m-faBase();
		display: inline-block;
		min-width: 1.4em;
		.m-faContent(@fa-var-wallet, .88em);


	}
}

.block-outer-reward
{
	float: left;
}
